void asignarJuguetes(int m, int n, vector<string> tipos) {
  // Vector para almacenar la solución
  vector<int> solucion;
  // Función recursiva para backtracking
  void backtrack(int etapa) {
    if (etapa == 2 * n) {
      // Imprimir solución
    } else {
      for (int i = 0; i < m; ++i) {
        // Comprobar si es válida la asignación
        if (esValida(etapa, i, solucion, tipos)) {
          // Añadir juguete a la solución
          solucion.push_back(i);
          // Llamada recursiva
          backtrack(etapa + 1);
          // Retirar juguete de la solución
          solucion.pop_back();
        }
      }
    }
  }
  // Llamada inicial a la función de backtracking
  backtrack(0);
}
